INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f508d07d411dcaf7ec',NULL,'condition','/kәn''diʃәn/','n. 情况, 条件\nvt. 使健康, 以...为条件, 决定, 使适应\n[计] 条件；英英释义：n. a state at a particular time\nn. an assumption on which rests the validity or effect of something else\nn. a mode of being or form of existence of a person or thing\nn. the state of (good) health (especially in the phrases `in condition'' or `in shape'' or `out of condition'' or `out of shape'')；词形变化：s:conditions/d:conditioned/i:conditioning/p:conditioned/3:conditions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_616806eeb489852530',NULL,'conduct','/''kɔndʌkt, -dәkt/','n. 行为, 举动, 指导\nvt. 为人, 指挥, 管理, 实施\nvi. 领导, 传导, 指挥；英英释义：v. direct the course of; manage or control\nv. lead, as in the performance of a composition; Barenboim conducted the Chicago symphony for years"\nv. lead musicians in the performance of；词形变化：d:conducted/i:conducting/p:conducted/3:conducts','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_943ad196445f47f172',NULL,'conductor','/kәn''dʌktә/','n. 领导者, 指挥者, 售票员, 向导\n[化] 导体；英英释义：n. the person who leads a musical group\nn. a substance that readily conducts e.g. electricity and heat\nn. the person who collects fares on a public conveyance\nn. a device designed to transmit electricity, heat, etc.；词形变化：s:conductors','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
