INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c64a829b0ef9c3b401',NULL,'conference','/''kɒnfәrәns/','n. 会议\n[经] 会议, 讨论会, 协商会；英英释义：n. a prearranged meeting for consultation or exchange of information or discussion (especially one with a formal agenda)\nn. a discussion among participants who have an agreed (serious) topic；词形变化：s:conferences','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
