INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6028235ff402e46bf8',NULL,'constant','/''kɒnstәnt/','n. 常数, 恒量\na. 不变的, 一定的, 时常的\n[计] 常量; 常数; 恒值；英英释义：n. a quantity that does not vary\nn. a number representing a quantity assumed to have a fixed value in a specified mathematical context\na. steadfast in purpose or devotion or affection；词形变化：s:constants','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_70fe9f61d3f7562429',NULL,'constituent','/kәn''stitjuәnt/','n. 成分, 选民, 构成物\na. 构成的, 组织的, 选举的；英英释义：n. a member of a constituency; a citizen who is represented in a government by officials for whom he or she votes\nn. (grammar) a word or phrase or clause forming part of a larger grammatical construction\ns. constitutional in the structure of something (especially your physical makeup)；词形变化：s:constituents','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8944f5135ef0ec4c6f',NULL,'constitute','/kәn''stitjut/','vt. 构成, 组成, 任命\n[建] 构造, 组成；英英释义：v. form or compose；词形变化：3:constitutes/p:constituted/d:constituted/i:constituting','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a27b323a46b55f598c',NULL,'constitution','/.kɒnsti''tju:ʃәn/','n. 构成, 宪法, 体格\n[医] 体质; 结构, 组织；英英释义：n. the act of forming or establishing something\nn. the way in which someone or something is composed\nn. a United States 44-gun frigate that was one of the first three naval ships built by the United States; it won brilliant victories over British frigates during the War of 1812 and is without doubt the most famous ship in the history of the United States Navy; it has been rebuilt and is anchored in the Charlestown Navy Yard in Boston；词形变化：s:constitutions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('ee64610c-4a83-45a0-9005-6b176813da70',NULL,'constrain','/kәn''strein/','vt. 强迫, 限制, 关押；英英释义：v hold back\nv restrict；词形变化：d:constrained/i:constraining/3:constrains/p:constrained','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_bce91d7c9f73d604b8',NULL,'construct','/kәn''strʌkt/','vt. 构造, 建造, 对...进行构思, 作图\nn. 构成物；英英释义：v. make by combining materials and parts\nv. draw with suitable instruments and under specified conditions\nv. create by linking linguistic units\nv. create by organizing and linking ideas, arguments, or concepts；词形变化：d:constructed/i:constructing/s:constructs/3:constructs/p:constructed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1fbf041b5a83bc2f4c',NULL,'construction','/kәn''strʌkʃәn/','n. 建筑, 构造, 建筑物\n[化] 施工；英英释义：n. the act of constructing something\nn. a group of words that form a constituent of a sentence and are considered as a single unit\nn. the creation of a construct; the process of combining ideas into a congruous object of thought\nn. drawing a figure satisfying certain conditions as part of solving a problem or proving a theorem；词形变化：s:constructions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
