INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_454c72c0d180bd43ea',NULL,'consume','/kәn''sju:m/','vt. 消耗, 消费, 消灭\nvi. 耗尽, 毁灭；英英释义：v. serve oneself to, or consume regularly\nv. spend extravagantly\nv. destroy completely\nv. use up (resources or materials)；词形变化：d:consumed/i:consuming/p:consumed/3:consumes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
