INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_34ac033ebf9d460992',NULL,'contain','/kәn''tein/','vt. 包含, 容纳, 控制\nvi. 自制；英英释义：v. be divisible by\nv. be capable of holding or containing；词形变化：3:contains/i:containing/p:contained/d:contained','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_cd6875d81adca3a8d0',NULL,'container','/kәn''teinә/','n. 容器, 集装箱\n[化] 集装箱; 贮存箱; 容器(任何一种)；英英释义：n. any object that can be used to hold things (especially a large metal boxlike object of standardized dimensions that can be loaded from one form of transport to another)；词形变化：s:containers','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
