INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('f0d4315d-6cb2-4734-a42b-634a9936ddcc',NULL,'contemplate','/''kɒntempleit/','vt. 注视, 沉思, 盘算\nvi. 冥思苦想；英英释义：v. look at thoughtfully; observe deep in thought\nv. consider as a possibility；词形变化：i:contemplating/d:contemplated/p:contemplated/3:contemplates','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_04a30d0b83217834fa',NULL,'contemporary','/kәn''tempәrәri/','n. 同时代的人\na. 同时代的, 属于同一时期的；英英释义：n. a person of nearly the same age as another\ns. characteristic of the present\ns. belonging to the present time；词形变化：s:contemporaries','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('fb320749-e262-4e4d-a515-5a23533af713',NULL,'contempt','/kәn''tempt/','n. 轻视, 轻蔑\n[法] 藐视, 侮辱, 轻视；英英释义：n. lack of respect accompanied by a feeling of intense dislike\nn. a manner that is generally disrespectful and contemptuous\nn. open disrespect for a person or thing\nn. a willful disobedience to or disrespect for the authority of a court or legislative body；词形变化：s:contempts','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3ff886e875515fdc0f',NULL,'contend','/kәn''tend/','vi. 奋斗, 斗争, 竞争\nvt. 为...斗争；英英释义：v. maintain or assert\nv. be engaged in a fight; carry on a fight；词形变化：3:contends/p:contended/d:contended/i:contending','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a9831fcdfd0e4661a5',NULL,'content','/kәn''tent/','n. 内容, 满足, 意义, 要旨\na. 满足的, 满意的\nvt. 使...满足, 使...安心\n[计] 内容；英英释义：n. everything that is included in a collection and that is held or included in something\nn. the proportion of a substance that is contained in a mixture or alloy etc.\nn. the sum or range of what has been perceived, discovered, or learned\nv. satisfy in a limited way；词形变化：s:contents/p:contented/d:contented/i:contenting/3:contents','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b00b6c0f84f51fa63d',NULL,'contention','/kәn''teinʃәn/','n. 争论, 争辩, 所持的论点\n[计] 争用；英英释义：n. a point asserted as part of an argument；词形变化：s:contentions','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_415c1a47cbcb412cb9',NULL,'contest','/''kɒntest/','n. 竞赛, 争论\nvt. 竞争, 争取, 争辩\nvi. 竞争；英英释义：n. an occasion on which a winner is selected from among two or more contestants\nn. a struggle between rivals\nv. to make the subject of dispute, contention, or litigation；词形变化：s:contests/d:contested/i:contesting/p:contested/3:contests','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ded3095095ff4cd98b',NULL,'context','/''kɒntekst/','n. 上下文, 背景, 来龙去脉\nn. 上下文\n[计] 上下文；英英释义：n. discourse that surrounds a language unit and helps to determine its interpretation\nn. the set of facts or circumstances that surround a situation or event；词形变化：s:contexts','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_015888276210a5f86d',NULL,'continent','/''kɒntinәnt/','n. 大陆, 洲\na. 自制的；英英释义：n. one of the large landmasses of the earth\nn. the European mainland\na. having control over urination and defecation；词形变化：s:continents','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_739463c69ed243dc07',NULL,'continual','/kәn''tinjuәl/','a. 持续不断的, 继续的\n[建] 连续的；英英释义：a. occurring without interruption; chiefly restricted to what recurs regularly or frequently in a prolonged and closely spaced series\ns. `continual'' (meaning seemingly uninterrupted) is often used interchangeably with `continuous'' (meaning without interruption)','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6f464486c1645d7f32',NULL,'continue','/kәn''tinju:/','vi. 继续, 延续, 延长\nvt. 使继续, 使延长；英英释义：v. continue a certain state, condition, or activity\nv. continue talking\nv. keep or maintain in unaltered condition; cause to remain or last\nv. do something repeatedly and showing no intention to stop；词形变化：p:continued/3:continues/d:continued/i:continuing','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fe54186c40dac80a16',NULL,'continuous','/kәn''tinjuәs/','a. 连续的, 继续的, 连续不断的\n[计] 连续的；英英释义：a. continuing in time or space without interruption\na. of a function or curve; extending without break or irregularity','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e97532db2cc2654833',NULL,'contract','/''kɒntrækt/','n. 合约, 婚约, 契约\nvt. 使皱缩, 使缩短, 感染, 订约, 缔结\nvi. 皱缩, 订约, 收缩；英英释义：n. a binding agreement between two or more persons that is enforceable by law\nn. (contract bridge) the highest bid becomes the contract setting the number of tricks that the bidder must make\nn. a variety of bridge in which the bidder receives points toward game only for the number of tricks he bid\nv. enter into a contractual arrangement；词形变化：s:contracts/d:contracted/i:contracting/p:contracted/3:contracts','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_abff161e86fadf62bc',NULL,'contradict','/.kɒntrә''dikt/','vt. 反驳, 与...抵触, 与...矛盾\nvi. 反驳；英英释义：v. be in contradiction with\nv. deny the truth of；词形变化：3:contradicts/d:contradicted/p:contradicted/i:contradicting','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('33f1442b-8057-489a-b30a-bdf1a4a32a88',NULL,'contradiction','/.kɒntrә''dikʃәn/','n. 反驳, 矛盾\n[法] 矛盾, 否认, 反驳；英英释义：n. opposition between two conflicting forces or ideas\nn. (logic) a statement that is necessarily false\nn. the speech act of contradicting someone；词形变化：s:contradictions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_17bbfb153a54138f33',NULL,'contrary','/''kɒntrәri/','a. 相反的, 矛盾的, 对立的\nn. 相反, 对立面\nadv. 相反地；英英释义：n. exact opposition\nn. a logical relation such that two propositions are contraries if both cannot be true but both can be false\ns. very opposed in nature or character or purpose\ns. of words or propositions so related that both cannot be true but both may be false；词形变化：s:contraries','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f08fdc55ba44deb66e',NULL,'contrast','/kәn''træst/','n. 差别, 对比, 对照物\nvt. 使对比\nvi. 成对照\n[计] 反差; 对比度；英英释义：n. the opposition or dissimilarity of things that are compared\nn. the act of distinguishing by comparing differences\nn. the perceptual effect of the juxtaposition of very different colors\nn. the range of optical density and tone on a photographic negative or print (or the extent to which adjacent areas on a television screen differ in brightness)；词形变化：s:contrasts/3:contrasts/d:contrasted/p:contrasted/i:contrasting','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2e92b13d2b90469ed1',NULL,'contribute','/kәn''tribju:t/','vt. 有助于, 捐助, 投稿\nvi. 出力, 捐献, 投稿；英英释义：v. contribute to some cause\nv. be conducive to；词形变化：d:contributed/i:contributing/p:contributed/3:contributes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3d55d25ea2207bfc77',NULL,'contribution','/.kɒntri''bju:ʃәn/','n. 捐助, 捐助之物, 贡献\n[经] 贡献, 捐款, 补助品；英英释义：n. the part played by a person in bringing about a result\nn. a voluntary gift (as of money or service or ideas) made to some worthwhile cause\nn. act of giving in common with others for a common purpose especially to a charity\nn. an amount of money contributed；词形变化：s:contributions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
