INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fceb3d380284d6b5e9',NULL,'convenience','/kә''vi:njәns/','n. 方便, 便利的事物, 方便的时候；英英释义：n. the state of being suitable or opportune\nn. the quality of being useful and convenient；词形变化：s:conveniences','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
