INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_33eef96399e2eda079',NULL,'convention','/kәn''venʃәn/','n. 大会, 协定, 惯例, 约定\n[计] 约定；英英释义：n. a large formal assembly\nn. something regarded as a normative example\nn. (diplomacy) an international agreement\nn. the act of convening；词形变化：s:conventions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('b6d22cbc-46a6-46fe-a9bc-216fa4130118',NULL,'conventional','/kәn''venʃәnl/','a. 传统的, 习惯的, 约定的\n[经] 惯例的, 常规的, 传统的；英英释义：a. following accepted customs and proprieties\ns. conforming with accepted standards\na. (weapons) using energy for propulsion or destruction that is not nuclear energy\na. unimaginative and conformist','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
