INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_65226073c5b90f980e',NULL,'conversion','/kәn''vә:ʃәn/','n. 转变, 转换, 改变宗教信仰, 换位法\n[计] 转换；英英释义：n. an event that results in a transformation\nn. a change in the units or form of an expression: "conversion from Fahrenheit to Centigrade"\nn. a successful free throw or try for point after a touchdown\nn. a spiritual enlightenment causing a person to lead a new life；词形变化：s:conversions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e28450140d26fa5e31',NULL,'convert','/kәn''vә:t/','n. 皈依者, 改变宗教信仰者\nvt. 使改变信仰, 转换, 兑换, 倒置\nvi. 皈依\n[计] 转换；英英释义：n. a person who has been converted to another religious or political belief\nv. change from one system to another or to a new plan or policy\nv. change the nature, purpose, or function of something\nv. change religious beliefs, or adopt a religious belief；词形变化：d:converted/i:converting/p:converted/3:converts/s:converts','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f0b7385f292c0c1272',NULL,'convey','/kәn''vei/','vt. 传达, 运输, 转让\n[经] 转让(财产等), 搬运；英英释义：v. make known; pass on, of information\nv. transfer to another\nv. transmit a title or property；词形变化：d:conveyed/i:conveying/3:conveys/p:conveyed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ee0f5e29d95b1957e9',NULL,'convict','/kәn''vikt/','n. 囚犯, 罪犯\nvt. 宣告有罪, 使知罪；英英释义：n. a person serving a sentence in a jail or prison\nn. a person who has been convicted of a criminal offense\nv. find or declare guilty；词形变化：d:convicted/s:convicts/i:convicting/p:convicted/3:convicts','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ed9c019a8ae0477608',NULL,'conviction','/kәn''vikʃәn/','n. 定罪, 信服, 坚信\n[法] 定罪, 证明有罪, 判罪；英英释义：n. an unshakable belief in something without need for proof or evidence\nn. (criminal law) a final judgment of guilty in a criminal case and the punishment that is imposed；词形变化：s:convictions','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7997497854f33eaea3',NULL,'convince','/kәn''vins/','vt. 说服, 使相信\n[法] 使确信, 使信服, 使人认识错误；英英释义：v make (someone) agree, understand, or realize the truth or validity of something；词形变化：d:convinced/p:convinced/i:convincing/3:convinces','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
