INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4be090d838b29112cb',NULL,'coordinate','/kәu''ɒ:dineit/','n. 同等的人(或物), 坐标\na. 同等的, 并列的\nv. (使)协调；英英释义：n. a number that identifies a position relative to an axis\nv. bring into common action, movement, or condition\nv. be co-ordinated\ns. of equal importance, rank, or degree；词形变化：s:coordinates/i:coordinating/d:coordinated/p:coordinated/3:coordinates','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
