INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_345de06c80361543f9',NULL,'copyright','/''kɒpirait/','n. 版权, 著作权\n[法] 著作权；英英释义：n. a document granting exclusive right to publish and sell literary or musical or artistic work\nv. secure a copyright on a written work；词形变化：s:copyrights/i:copyrighting/p:copyrighted/3:copyrights/d:copyrighted','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
