INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1f6d31b0460ca894b3',NULL,'crisis','/''kraisis/','n. 危机, 危险期, 紧要关头\n[医] 危象; 骤退, 临界, 极期；英英释义：n. an unstable situation of extreme danger or difficulty\nn. a crucial stage or turning point in the course of something；词形变化：s:crises','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
