INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_deac8af91d4201cba6',NULL,'criterion','/krai''tiәriәn/','n. 标准, 准则, 规范\n[化] 判据；英英释义：n. the ideal in terms of which something can be judged；词形变化：s:criteria','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
