INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a1aa2a709d15f326a3',NULL,'critical','/''kritikәl/','a. 批评的, 决定性的, 危险的, 临界的\n[医] 危象的; 临界的, 极期的；英英释义：a. marked by a tendency to find and call attention to errors and flaws\na. at or of a point at which a property or phenomenon suffers an abrupt change especially having enough mass to sustain a chain reaction\na. characterized by careful evaluation and judgment\ns. urgently needed; absolutely necessary','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
