INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_539c6795f73bd62d79',NULL,'crowd','/kraud/','n. 群众, 一伙人\nvt. 拥挤, 挤满, 挤进；英英释义：n. a large number of things or people considered together\nn. an informal body of friends\nv. fill or occupy to the point of overflowing\nv. to gather together in large numbers；词形变化：s:crowds/p:crowded/d:crowded/i:crowding/3:crowds','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b90cc933a247c17770',NULL,'crown','/kraun/','n. 王冠, 王权, 顶点\nvt. 使成王, 加冕, 居...之顶；英英释义：n. the Crown (or the reigning monarch) as the symbol of the power and authority of a monarchy\nn. the part of a tooth above the gum that is covered with enamel\nn. a wreath or garland worn on the head to signify victory\nn. an ornamental jeweled headdress signifying sovereignty；词形变化：d:crowned/s:crowns/p:crowned/i:crowning/3:crowns','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('9c9ee7bd-c60f-4a59-9358-7ea37038e50e',NULL,'crucial','/''kru:ʃәl/','a. 决定性的, 重要的, 严厉的\n[医] 十字形的; 决断的, 定局的；英英释义：a. of extreme importance; vital to the resolution of a crisis\ns. having crucial relevance','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7baa2cb6259ea671c4',NULL,'crude','/kru:d/','a. 天然的, 未成熟的, 粗糙的, 粗鲁的\nn. 天然的物质；英英释义：s. not carefully or expertly made\ns. conspicuously and tastelessly indecent\ns. belonging to an early stage of technical development; characterized by simplicity and (often) crudeness\ns. not processed or subjected to analysis；词形变化：r:cruder/t:crudest/s:crudes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_14a4332fe465868efd',NULL,'cruel','/''kru:әl/','a. 残酷的, 令人极痛苦的\n[法] 残忍的, 残酷的；英英释义：s (of persons or their actions) able or disposed to inflict pain or suffering；词形变化：t:cruellest/r:crueller','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ebc50bdf447cf2b8cb',NULL,'cruise','/kru:z/','n. 巡航, 巡弋, 漫游\nv. 巡航, 巡弋, 漫游；英英释义：n. an ocean trip taken for pleasure\nv. drive around aimlessly but ostentatiously and at leisure\nv. travel at a moderate speed\nv. look for a sexual partner in a public place；词形变化：i:cruising/s:cruises/p:cruised/d:cruised/3:cruises','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
