INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e7d2d38c9caa035545',NULL,'crystal','/''kristl/','n. 水晶, 水晶装饰品, 结晶\na. 水晶的, 水晶一样的, 透明的；英英释义：n. a solid formed by the solidification of a chemical and having a highly regular atomic structure\nn. a crystalline element used as a component in various electronic devices\nn. a rock formed by the solidification of a substance; has regularly repeating internal structure; external plane faces\nn. glassware made of quartz；词形变化：s:crystals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d17aa0fa98e80814d5',NULL,'cube','/kju:b/','n. 立方体, 立方\n[机] 立方体, 立方；英英释义：n. a hexahedron with six equal squares as faces\nn. the product of three equal terms\nn. any of several tropical American woody plants of the genus Lonchocarpus whose roots are used locally as a fish poison and commercially as a source of rotenone\nn. a block in the (approximate) shape of a cube；词形变化：s:cubes/d:cubed/i:cubing/p:cubed/3:cubes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_cb3600bc53b6cbfa85',NULL,'cucumber','/''kju:kәmbә/','n. 黄瓜\n[医] 黄瓜, 胡瓜；英英释义：n. a melon vine of the genus Cucumis; cultivated from earliest times for its cylindrical green fruit\nn. cylindrical green fruit with thin green rind and white flesh eaten as a vegetable; related to melons；词形变化：s:cucumbers','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
