INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_db92075e76400e5504',NULL,'curiosity','/.kjuәri''ɒsiti/','n. 好奇心, 新奇的事物, 珍品；英英释义：n. a state in which you want to learn more about something；词形变化：s:curiosities','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
