INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1be108773cdf36deef',NULL,'curl','/kә:l/','n. 拳曲, 鬈发\nvt. 弄卷\nvi. 拳曲, 弯曲；英英释义：n. American chemist who with Richard Smalley and Harold Kroto discovered fullerenes and opened a new branch of chemistry (born in 1933)\nv. form a curl, curve, or kink\nv. twist or roll into coils or ringlets\nv. play the Scottish game of curling；词形变化：s:curls/p:curled/i:curling/d:curled/3:curls','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
