INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_20d09551a1908ec543',NULL,'depression','/di''preʃәn/','n. 不景气, 消沉, 沮丧, 洼地\n[医] 抑郁[症], 阻抑, 压低, 凹, 窝, 衰退, 俯角；英英释义：n. a mental state characterized by a pessimistic sense of inadequacy and a despondent lack of activity\nn. a long-term economic state characterized by unemployment and low prices and low levels of trade and investment\nn. sad feelings of gloom and inadequacy\nn. a period during the 1930s when there was a worldwide economic depression and mass unemployment；词形变化：s:depressions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
