INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_54ea1334433a13339d',NULL,'drip','/drip/','n. 水滴\nv. (使)滴下；英英释义：n. flowing in drops; the formation and falling of drops of liquid\nn. the sound of a liquid falling drop by drop\nn. (architecture) a projection from a cornice or sill designed to protect the area below from rainwater (as over a window or doorway)\nv. fall in drops；词形变化：i:dripping/p:dripped/s:drips/3:drips/d:dripped','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
