INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_38d31be04c0d3d62e3',NULL,'false','/fɒ:ls/','a. 错误的, 虚伪的, 假的, 不老实的\nadv. 不准确地, 欺诈地；英英释义：a. not in accordance with the fact or reality or actuality\ns. arising from error\ns. erroneous and usually accidental\ns. deliberately deceptive','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
