INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6e2149aab462364728',NULL,'farther','/''fɑ:ðә/','a. 更远的, 进一步的\nadv. 更远的, 此外, far的比较级；英英释义：s. more distant in especially space or time\nr. to or at a greater distance in time or space (`farther'' is used more frequently than `further'' in this physical sense)；词形变化：0:far/1:r','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
