INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4e25caea5397f4e865',NULL,'fashion','/''fæʃәn/','n. 流行, 风尚, 时样\nvt. 形成, 造, 作；英英释义：n. characteristic or habitual practice\nn. the latest and most admired style in clothes and cosmetics and behavior\nn. consumer goods (especially clothing) in the current mode\nv. make out of components (often in an improvising manner)；词形变化：d:fashioned/s:fashions/p:fashioned/i:fashioning/3:fashions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ff4a1acd4061a0928b',NULL,'fashionable','/''fæʃәnәbl/','a. 时髦的, 上流社会的, 流行的；英英释义：a. being or in accordance with current social fashions\ns. patronized by；词形变化：s:fashionables','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
