INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_dc99d2f36438eb0c88',NULL,'fat','/fæt/','n. 脂肪, 脂油, 肥肉\na. 肥的, 胖的, 油腻的\nn. 文件分配表\n[计] 文件分配表；英英释义：n. a soft greasy substance occurring in organic tissue and consisting of a mixture of lipids (mostly triglycerides)\na. having an (over)abundance of flesh\ns. having a relatively large diameter\ns. lucrative；词形变化：s:fats/r:fatter/t:fattest/i:fatting/p:fatted/3:fats/d:fatted','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b15bcf9fcb0edd8bad',NULL,'fatal','/''feitәl/','a. 致命的, 重大的, 命运注定的, 粗心的, 不幸的\n[医] 致命的, 致死的；英英释义：a. bringing death\ns. controlled or decreed by fate; predetermined','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_11d545f1fddfe46f25',NULL,'fate','/feit/','n. 命运, 运气\nvt. 注定；英英释义：n an event (or a course of events) that will inevitably happen in the future\nn the ultimate agency regarded as predetermining the course of events (often personified as a woman)\nn your overall circumstances or condition in life (including everything that happens to you)\nv decree or designate beforehand；词形变化：s:fates/d:fated/t:fatest/i:fating/p:fated/3:fates','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0fe7a3f03ca90e8aeb',NULL,'fatigue','/fә''ti:g/','n. 疲乏, 疲劳\nvt. 使疲劳, 使心智衰弱\nvi. 疲劳\na. 疲劳的；英英释义：n. temporary loss of strength and energy resulting from hard physical or mental work\nn. used of materials (especially metals) in a weakened state caused by long stress\nn. (always used with a modifier) boredom resulting from overexposure to something；词形变化：s:fatigues/d:fatigued/p:fatigued/i:fatiguing/3:fatigues','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d666312862274e0455',NULL,'fault','/fɒ:lt/','n. 过错, 故障, 毛病\nvt. 挑剔\nvi. 产生断层, 弄错\n[计] 故障；英英释义：n. (geology) a crack in the earth''s crust resulting from the displacement of one side with respect to the other\nn. (electronics) equipment failure attributable to some defect in a circuit (loose connection or insulation failure or short circuit etc.)\nn. responsibility for a bad situation or event\nn. (sports) a serve that is illegal (e.g., that lands outside the prescribed area)；词形变化：s:faults/d:faulted/p:faulted/i:faulting/3:faults','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_598c021995017b708a',NULL,'faulty','/''fɒ:lti/','a. 有过失的, 有缺点的, 不完美的, 应受责备的\n[经] 缺点多的；英英释义：s. characterized by errors; not agreeing with a model or not following established rules; the wrong side of the road"','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
