INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_97fc1e853290cfb317',NULL,'favorable','/''feivәrәbl/','a. 有利的, 赞许的, 良好的；英英释义：a. encouraging or approving or pleasing\na. (of winds or weather) tending to promote or facilitate\ns. occurring at a convenient or suitable time','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_188868b88918324e09',NULL,'favorite','/''feivәrit/','n. 喜欢的事物, 幸运儿\na. 特别受喜爱的, 喜爱的, 宠爱的, 中意的；英英释义：n. something regarded with special favor or liking\ns. appealing to the general public；词形变化：s:favorites','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
